const site = $json;
const ctx = $('Set SharePoint Context').first().json;
return [{ json: { ...ctx, site_id: site.id } }];

const ctx = $('Build Site Context').first().json;
const drives = $json.value || [];
const preferred = drives.find(d => ['Documents', 'Shared Documents'].includes(d.name)) || drives[0];
if (!preferred) throw new Error('No SharePoint drive found for site');
return [{ json: { ...ctx, drive_id: preferred.id, drive_name: preferred.name } }];

const meta = $json;
const ctx = $('Pick SharePoint Drive').first().json;
return [{
  json: {
    ...ctx,
    workbook_item_id: meta.id,
    workbook_web_url: meta.webUrl || '',
    workbook_file_name: meta.name || ctx.workbook_name
  }
}];

const rows = $input.all().map((i, idx) => ({ ...i.json, __sheet_row_number: idx + 2 }));

function pick(obj, keys) {
  for (const key of keys) {
    if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') {
      return obj[key];
    }
  }
  return '';
}

function normStatus(value) {
  const s = String(value || '').trim().toUpperCase();
  if (s === 'COMPLETE') return 'COMPLETED';
  return s;
}

const normalised = rows.map(r => ({
  raw: r,
  source_row_number: r.__sheet_row_number,
  client_name: pick(r, ['client_name', 'Client_Name']),
  client_email: pick(r, ['client_email', 'Client_Email']),
  sector: pick(r, ['sector', 'Sector']),
  market_count: pick(r, ['market_count', 'Market_Count']),
  maturity_stage: pick(r, ['maturity_stage', 'Maturity_Stage']),
  gdrive_folder_id: pick(r, ['gdrive_folder_id', 'GDrive_Folder_ID', 'sharepoint_folder_id']),
  audit_id: pick(r, ['Audit_ID', 'audit_id']),
  status: normStatus(pick(r, ['Status', 'status'])),
  created_at: pick(r, ['created_at', 'Created_At']),
  completed_at: pick(r, ['Completed_At', 'completed_at'])
})).filter(r => r.client_name || r.audit_id || r.gdrive_folder_id);

const readyRows = normalised.filter(r => r.status === 'READY');

if (readyRows.length === 0) {
  throw new Error(
    'No client queue row found with Status = READY. Found statuses: ' +
    normalised.map(r => `${r.client_name || r.audit_id || 'Unknown'}=${r.status || '[blank]'}`).join(', ')
  );
}

if (readyRows.length > 1) {
  throw new Error(
    'Multiple READY rows found in Clients_Queue: ' +
    readyRows.map(r => r.client_name || r.audit_id || 'Unknown').join(', ')
  );
}

const active = readyRows[0];

return [{
  json: {
    client_name: active.client_name || 'Unknown Client',
    client_email: active.client_email || '',
    sector: active.sector || 'Unknown',
    market_count: active.market_count || '',
    maturity_stage: active.maturity_stage || 'Unknown',
    gdrive_folder_id: active.gdrive_folder_id || '',
    Audit_ID: active.audit_id || '',
    Status: active.status,
    created_at: active.created_at || '',
    Completed_At: active.completed_at || '',
    source_row_number: active.source_row_number
  }
}];

function safeFirst(nodeName) {
  try {
    const n = $(nodeName);
    if (!n || !n.isExecuted) return {};
    return n.first().json || {};
  } catch (e) {
    return {};
  }
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (v !== null && v !== undefined && String(v).trim() !== '') {
      return v;
    }
  }
  return '';
}

function str(v, fallback = '') {
  if (v === null || v === undefined) return fallback;
  const s = String(v).trim();
  return s === '' ? fallback : s;
}

const active = safeFirst('Select Active Client Queue Row');
const trigger = safeFirst('Manual Trigger - Start Audit');
const vars = safeFirst('Variables and context');
const upload = safeFirst('Upload file') || safeFirst('Upload File');

const client_name = str(firstNonEmpty(
  active.client_name,
  active.Client_Name,
  trigger.client_name,
  trigger.Client_Name,
  vars.client_name,
  vars.Client_Name,
  upload.client_name,
  upload.Client_Name,
  'Unknown Client'
));

const client_email = str(firstNonEmpty(
  active.client_email,
  active.Client_Email,
  trigger.client_email,
  trigger.Client_Email,
  vars.client_email,
  vars.Client_Email,
  upload.client_email,
  upload.Client_Email,
  'unknown@wpp.com'
));

const sector = str(firstNonEmpty(
  active.sector,
  active.Sector,
  trigger.sector,
  trigger.Sector,
  vars.sector,
  vars.Sector,
  upload.sector,
  upload.Sector,
  'Unknown'
));

const market_count = firstNonEmpty(
  active.market_count,
  active.Market_Count,
  trigger.market_count,
  trigger.Market_Count,
  vars.market_count,
  vars.Market_Count,
  upload.market_count,
  upload.Market_Count,
  ''
);

const maturity_stage = str(firstNonEmpty(
  active.maturity_stage,
  active.Maturity_Stage,
  trigger.maturity_stage,
  trigger.Maturity_Stage,
  vars.maturity_stage,
  vars.Maturity_Stage,
  upload.maturity_stage,
  upload.Maturity_Stage,
  'Unknown'
));

const gdrive_folder_id = str(firstNonEmpty(
  active.gdrive_folder_id,
  active.GDrive_Folder_ID,
  active.sharepoint_folder_id,
  active.SharePoint_Folder_ID,
  ''
));

const audit_id = str(firstNonEmpty(
  active.Audit_ID,
  active.audit_id,
  ''
));

const status = str(firstNonEmpty(
  active.Status,
  active.status,
  'NEW'
)).toUpperCase();

const created_at = str(firstNonEmpty(
  active.created_at,
  active.Created_At,
  new Date().toISOString()
));

const completed_at = str(firstNonEmpty(
  active.Completed_At,
  active.completed_at,
  ''
));

const sharepoint_folder_id = gdrive_folder_id;
const excel_workbook_name = 'Audit_Master_LIVE.xlsx';
const audit_timestamp = new Date().toISOString();

return [{
  json: {
    client_name,
    client_email,
    sector,
    market_count,
    maturity_stage,
    gdrive_folder_id,
    audit_id,
    status,
    created_at,
    completed_at,
    sharepoint_folder_id,
    excel_workbook_name,
    audit_timestamp,
    source_row_number: active.source_row_number || ''
  }
}];

const cfg = $('Dynamic Client Config').first().json;
const wb = $('Build Workbook Context').first().json;
const row = Number(cfg.source_row_number || 0);
if (!row) throw new Error('Missing source_row_number for queue status update');
return [{
  json: {
    drive_id: wb.drive_id,
    workbook_item_id: wb.workbook_item_id,
    range_address: `Clients_Queue!G${row}:H${row}`,
    values: [["PROCESSING", ""]]
  }
}];

const cfg = $('Dynamic Client Config').first().json;
const sp = $('Set SharePoint Context').first().json;
const raci = $('1.2 RACI Matrix').all().map(i => i.json).filter(r => Object.values(r).some(v => String(v || '').trim() !== ''));
const tools = $('1.3 Tools Inventory').all().map(i => i.json);
const kpis = $('1.4 KPI Snapshot').all().map(i => i.json).filter(r => Object.values(r).some(v => String(v || '').trim() !== ''));
const benchmarks = $('2.4a Benchmarks').all().map(i => i.json).filter(r => Object.values(r).some(v => String(v || '').trim() !== ''));

const audit_id = cfg.audit_id;
const now = new Date().toISOString();
const run_id = `RUN-${audit_id}-${Date.now()}`;

function pick(obj, keys, fallback = '') {
  for (const key of keys) {
    if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') return obj[key];
  }
  return fallback;
}

const raciOutput = raci.map((r, idx) => ({
  row_id: `${audit_id}-RACI-${idx + 1}`,
  audit_id,
  process: pick(r, ['process', 'Process']),
  responsible: pick(r, ['responsible', 'Responsible']),
  accountable: pick(r, ['accountable', 'Accountable']),
  consulted: pick(r, ['consulted', 'Consulted']),
  tools_used: pick(r, ['tools_used', 'Tools_Used', 'tool', 'Tool']),
  automation_level: pick(r, ['automation_level', 'Automation_Level']),
  informed: pick(r, ['informed', 'Informed']),
  notes: pick(r, ['notes', 'Notes']),
  created_at: now
}));

const benchmarkMap = new Map();
for (const b of benchmarks) {
  const metric = String(pick(b, ['metric', 'Metric'])).trim().toLowerCase();
  if (!metric) continue;
  benchmarkMap.set(metric, b);
}

function toNum(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

const kpiBenchmarking = kpis.map((k, idx) => {
  const metric = pick(k, ['metric', 'Metric']);
  const key = String(metric).trim().toLowerCase();
  const b = benchmarkMap.get(key) || {};
  const clientValue = toNum(pick(k, ['value', 'Value']));
  const industryAvg = toNum(pick(b, ['industry_avg', 'Industry_Avg', 'avg', 'Average']));
  const bestInClass = toNum(pick(b, ['best_in_class', 'Best_In_Class']));
  const direction = pick(k, ['direction', 'Direction'], pick(b, ['direction', 'Direction'], 'HIGHER_IS_BETTER'));
  const unit = pick(k, ['unit', 'Unit'], pick(b, ['unit', 'Unit']));

  let gapVsAvgPct = '';
  if (clientValue !== null && industryAvg !== null && industryAvg !== 0) {
    gapVsAvgPct = (((clientValue - industryAvg) / industryAvg) * 100).toFixed(2);
  }

  let status = 'NO_BENCHMARK';
  if (industryAvg !== null && clientValue !== null) {
    if (String(direction).toUpperCase() === 'LOWER_IS_BETTER') {
      status = clientValue <= industryAvg ? 'ON_TRACK' : 'GAP';
    } else {
      status = clientValue >= industryAvg ? 'ON_TRACK' : 'GAP';
    }
  }

  return {
    row_id: `${audit_id}-KPI-${idx + 1}`,
    audit_id,
    client_name: cfg.client_name,
    sector: cfg.sector,
    metric,
    client_value: pick(k, ['value', 'Value']),
    industry_avg: industryAvg ?? pick(b, ['industry_avg', 'Industry_Avg', 'avg', 'Average'], ''),
    best_in_class: bestInClass ?? pick(b, ['best_in_class', 'Best_In_Class'], ''),
    direction,
    unit,
    gap_vs_avg_pct: gapVsAvgPct,
    status,
    opportunity_value: '',
    created_at: now
  };
});

const totalBaselineDays = 100;
const totalOrchestratedDays = 70;
const totalReductionPct = 30;
const totalOpportunityValue = '';
const overallStatus = 'COMPLETED';

const execSummaryMd = [
  `Client: ${cfg.client_name}`,
  `Audit ID: ${audit_id}`,
  `Sector: ${cfg.sector}`,
  `Maturity Stage: ${cfg.maturity_stage}`,
  `RACI rows: ${raciOutput.length}`,
  `KPI rows: ${kpiBenchmarking.length}`,
  `Generated at: ${now}`
].join('\n');

const auditReportTxt = [
  `AI Operating Model Audit`,
  `Client: ${cfg.client_name}`,
  `Audit ID: ${audit_id}`,
  `Sector: ${cfg.sector}`,
  `Maturity Stage: ${cfg.maturity_stage}`,
  `RACI output count: ${raciOutput.length}`,
  `KPI benchmarking count: ${kpiBenchmarking.length}`,
  `Tools input count: ${tools.length}`,
  `Run timestamp: ${now}`
].join('\n');

function encodePath(path) {
  return String(path || '')
    .split('/')
    .filter(Boolean)
    .map(p => encodeURIComponent(p))
    .join('/');
}

const reportFileName = `${cfg.client_name.replace(/\s+/g, '_')}__AI_Operating_Model_AUDIT__${audit_id}.txt`;
const libraryPath = encodePath(sp.library_folder_path);
const clientPath = encodePath(cfg.gdrive_folder_id);
const sitePath = encodePath(sp.site_path);
const optionalClientFolder = clientPath ? `/${clientPath}` : '';
const reportUrlPlaceholder = `https://${sp.tenant_domain}/sites/${sitePath}/${libraryPath}${optionalClientFolder}/${encodeURIComponent(reportFileName)}`;

const auditMasterRow = {
  row_id: `${audit_id}-MASTER-1`,
  audit_id,
  client_name: cfg.client_name,
  sector: cfg.sector,
  maturity_stage: cfg.maturity_stage,
  run_timestamp: now,
  total_baseline_days: totalBaselineDays,
  total_orchestrated_days: totalOrchestratedDays,
  total_reduction_pct: totalReductionPct,
  total_opportunity_value: totalOpportunityValue,
  overall_status: overallStatus,
  notes: '',
  run_id,
  report_url: reportUrlPlaceholder,
  recommended_scenario: 'BASELINE',
  npv: '',
  irr: '',
  recommendations_count: kpiBenchmarking.filter(x => x.status === 'GAP').length,
  raci_count: raciOutput.length,
  created_at: now
};

return [{
  json: {
    audit_id,
    run_id,
    now,
    client_name: cfg.client_name,
    sector: cfg.sector,
    maturity_stage: cfg.maturity_stage,
    gdrive_folder_id: cfg.gdrive_folder_id,
    auditMasterRow,
    raciOutput,
    kpiBenchmarking,
    exec_summary_md: execSummaryMd,
    audit_report_txt: auditReportTxt
  }
}];

const payload = $('Compose Audit Outputs').first().json;
const wb = $('Build Workbook Context').first().json;
const values = payload.raciOutput.map(r => ([
  r.row_id,
  r.audit_id,
  r.process,
  r.responsible,
  r.accountable,
  r.consulted,
  r.tools_used,
  r.automation_level,
  r.informed,
  r.notes,
  r.created_at
]));
return [{ json: { drive_id: wb.drive_id, workbook_item_id: wb.workbook_item_id, values } }];

const payload = $('Compose Audit Outputs').first().json;
const filename = `${payload.client_name.replace(/\s+/g, '_')}__EXEC_SUM__${payload.audit_id}.txt`;
const text = payload.exec_summary_md;
return [{
  json: { file_name: filename, folder_name: payload.gdrive_folder_id },
  binary: {
    data: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      mimeType: 'text/plain',
      fileName: filename
    }
  }
}];

const payload = $('Compose Audit Outputs').first().json;
const filename = `${payload.client_name.replace(/\s+/g, '_')}__AI_Operating_Model_AUDIT__${payload.audit_id}.txt`;
const text = payload.audit_report_txt;
return [{
  json: { file_name: filename, folder_name: payload.gdrive_folder_id },
  binary: {
    data: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      mimeType: 'text/plain',
      fileName: filename
    }
  }
}];

const cfg = $('Dynamic Client Config').first().json;
const wb = $('Build Workbook Context').first().json;
const row = Number(cfg.source_row_number || 0);
if (!row) throw new Error('Missing source_row_number for completed queue status update');
return [{
  json: {
    drive_id: wb.drive_id,
    workbook_item_id: wb.workbook_item_id,
    range_address: `Clients_Queue!G${row}:H${row}`,
    values: [["COMPLETED", new Date().toISOString()]]
  }
}];

const cfg = $('Dynamic Client Config').first().json;
const outputs = $('Compose Audit Outputs').first().json;
return [{
  json: {
    status: 'ok',
    client_name: cfg.client_name,
    audit_id: cfg.audit_id,
    queue_status: 'COMPLETED',
    client_folder: cfg.gdrive_folder_id,
    uploaded_files: [
      `${outputs.client_name.replace(/\s+/g, '_')}__EXEC_SUM__${outputs.audit_id}.txt`,
      `${outputs.client_name.replace(/\s+/g, '_')}__AI_Operating_Model_AUDIT__${outputs.audit_id}.txt`
    ],
    workbook: 'Audit_Master_LIVE.xlsx'
  }
}];
